function toOptionLabel(name: string) {
  if (name === "none") return "None Icon";

  return name
    .split("-")
    .filter(Boolean)
    .map((part) => part.charAt(0).toUpperCase() + part.slice(1))
    .join(" ");
}

export const ICON_ENUM_OPTIONS: Record<string, string> = Object.fromEntries(
  ICON_NAMES.map((name) => [toOptionLabel(name), name]),
);

export const ICON_ENUM_OPTIONS_WITH_NONE: Record<string, string> = {
  None: "",
  ...ICON_ENUM_OPTIONS,
};
